#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, int size, int offset) {
    int i = get_global_id(0);
    if (i != 0) return;

    int j, k;
    int bs = BLOCK_SIZE;

    for (int row = 0; row < bs; row++) {
        // Update Upper part (including diagonal) for this row
        for (j = row; j < bs; j++) {
            float sum = 0.0f;
            for (k = 0; k < row; k++) {
                sum += a[(offset + row) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
            }
            a[(offset + row) * size + (offset + j)] -= sum;
        }

        float diag = a[(offset + row) * size + (offset + row)];
        float inv_diag = 1.0f / diag;

        // Update Lower part for this row (columns below diagonal)
        for (j = row + 1; j < bs; j++) {
            float sum = 0.0f;
            for (k = 0; k < row; k++) {
                sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + row)];
            }
            a[(offset + j) * size + (offset + row)] = (a[(offset + j) * size + (offset + row)] - sum) * inv_diag;
        }
    }
}

__kernel void lud_perimeter(__global float* a, int size, int offset) {
    int idx = get_global_id(0);
    int bs = BLOCK_SIZE;
    int remaining = size - offset - bs;

    if (remaining <= 0) return;

    int chunks = remaining / bs;
    if (chunks <= 0) return;

    int total_tasks = 2 * chunks * bs;
    if (idx >= total_tasks) return;

    int block_idx = idx / bs;
    int inner_idx = idx % bs;

    int i, j, k;
    float sum;

    if (block_idx < chunks) {
        // Right perimeter: Update rows [offset, offset+bs-1], cols [offset+bs+block_idx*bs, ...]
        // Thread handles row 'inner_idx' of the diagonal block
        i = inner_idx;
        int col_start = offset + bs + block_idx * bs;

        for (j = 0; j < bs; j++) {
            sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (col_start + j)];
            }
            a[(offset + i) * size + (col_start + j)] -= sum;
        }
    } else {
        // Bottom perimeter: Update rows [offset+bs+(block_idx-chunks)*bs, ...], cols [offset, offset+bs-1]
        // Thread handles column 'inner_idx' of the diagonal block (which becomes the divisor)
        int row_start = offset + bs + (block_idx - chunks) * bs;
        j = inner_idx; // This is the column index within the bottom block strip (relative to offset)

        // We need to update all rows i in this block strip for column j
        for (i = 0; i < bs; i++) {
            sum = 0.0f;
            for (k = 0; k < j; k++) {
                sum += a[(row_start + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
            }
            float val = a[(row_start + i) * size + (offset + j)] - sum;
            a[(row_start + i) * size + (offset + j)] = val / a[(offset + j) * size + (offset + j)];
        }
    }
}

__kernel void lud_internal(__global float* a, int size, int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int bs = BLOCK_SIZE;
    int remaining = size - offset - bs;

    if (remaining <= 0) return;

    int chunks = remaining / bs;
    if (chunks <= 0) return;

    if (gx >= chunks || gy >= chunks) return;

    int row_start = offset + bs + gx * bs;
    int col_start = offset + bs + gy * bs;

    int i, j, k;

    // Each thread processes one block (gx, gy)
    for (i = 0; i < bs; i++) {
        for (j = 0; j < bs; j++) {
            float sum = 0.0f;
            for (k = 0; k < bs; k++) {
                // L part: from left perimeter (row_start+i, offset+k)
                // U part: from top perimeter (offset+k, col_start+j)
                sum += a[(row_start + i) * size + (offset + k)] * a[(offset + k) * size + (col_start + j)];
            }
            a[(row_start + i) * size + (col_start + j)] -= sum;
        }
    }
}
